<template><view class="page-shell"><view class="page-intro"><text class="eyebrow">服务反馈</text><text class="page-title">投诉处理记录</text><text class="page-desc">我们会持续跟进每一个问题</text></view><view v-if="complaintStore.loading" class="loading-wrap"><u-loading-icon size="28" color="#3A7BF7" /></view><empty-state v-else-if="!complaintStore.complaints.length" title="暂无投诉记录" description="遇到问题可从订单详情提交反馈" /><view v-else><view v-for="item in complaintStore.complaints" :key="item.complaintId" class="complaint-card" @click="goDetail(item.complaintId)"><view class="card-head"><text class="type">{{ item.typeText }}</text><text class="status" :class="`status-${item.status}`">{{ item.statusText }}</text></view><text class="content">{{ item.content }}</text><view class="card-foot"><text>{{ formatTime(item.createTime) }}</text><view class="track-link"><text>查看进度</text><u-icon name="arrow-right" size="14" color="#3A7BF7" /></view></view></view></view></view></template>
<script setup>import { onMounted } from 'vue'; import { useComplaintStore } from '@/store/complaint.js'; import EmptyState from '@/components/base/empty-state.vue'; const complaintStore = useComplaintStore(); onMounted(() => complaintStore.fetchComplaints()); function formatTime(value) { return value?.replace('T',' ').replace('+08:00','').slice(0,16) || '--' } function goDetail(id) { uni.navigateTo({ url: `/pages/complaint/complaint-detail?id=${id}` }) }</script>
<style lang="scss" scoped>.page-shell { min-height: 100vh; padding: 30rpx $spacing-base 50rpx; background: $page-gradient; }.eyebrow { display:block;color:$warning-color;font-size:$font-size-sm;font-weight:600; }.page-title { display:block;margin-top:8rpx;color:$text-color;font-size:38rpx;font-weight:700; }.page-desc { display:block;margin-top:8rpx;color:$text-color-hint;font-size:$font-size-sm; }.loading-wrap { padding:160rpx 0;display:flex;justify-content:center; }.complaint-card { margin-top:20rpx;padding:24rpx;border:$glass-border-soft;border-radius:28rpx;background:$surface-gradient;box-shadow:$shadow-sm; }.card-head,.card-foot { display:flex;align-items:center;justify-content:space-between; }.type { color:$text-color;font-size:$font-size-base;font-weight:700; }.status { padding:6rpx 14rpx;border-radius:$radius-round;font-size:$font-size-xs; }.status-0 { color:$warning-color;background:#fff2eb; }.status-1 { color:$primary-color;background:$primary-bg; }.status-2 { color:$success-color;background:#e9fbf7; }.status-3 { color:$info-color;background:#f0f3f7; }.content { display:-webkit-box;-webkit-box-orient:vertical;-webkit-line-clamp:2;overflow:hidden;margin-top:18rpx;color:$text-color-secondary;font-size:$font-size-sm;line-height:1.65; }.card-foot { margin-top:20rpx;padding-top:18rpx;border-top:1rpx solid $divider-color;color:$text-color-disabled;font-size:$font-size-xs; }.track-link { display:flex;align-items:center;gap:3rpx;color:$primary-color; }</style>
